<?php
 namespace WPAICG\Core; if (!defined('ABSPATH')) { exit; } class AIPKit_Event_Signature { public static function build(string $timestamp, string $body, string $secret): string { $normalized_secret = trim($secret); if ($normalized_secret === '') { return ''; } $signature = hash_hmac('sha256', $timestamp . '.' . $body, $normalized_secret); return 'sha256=' . $signature; } } 